var luminance = LandscapeMgr.getLuminance();
core.debug("Current landscape luminance: " + luminance);
if(luminance < 0.1) {
    core.debug("Very dark conditions");
}

var avgLum = LandscapeMgr.getAtmosphereAverageLuminance();
core.debug("Atmosphere average luminance: " + avgLum.toFixed(2) + " cd/m²");

if(avgLum > 1000) {
    core.debug("Daytime brightness");
} else if(avgLum > 10) {
    core.debug("Twilight");
} else {
    core.debug("Nighttime");
}

// Freeze atmosphere luminance at current value
var currentLum = LandscapeMgr.getAtmosphereAverageLuminance();
LandscapeMgr.setAtmosphereAverageLuminance(currentLum);
core.debug("Atmosphere luminance frozen at " + currentLum.toFixed(2));

// ... do something ...

// Unfreeze
LandscapeMgr.setAtmosphereAverageLuminance(-1.0);
core.debug("Atmosphere luminance unfrozen");

var landscapes = LandscapeMgr.getAllLandscapeNames();
core.debug("Available landscapes: " + landscapes.length);
for(var i = 0; i < landscapes.length; i++) {
    core.debug((i+1) + ". " + landscapes[i]);
}

var userLandscapes = LandscapeMgr.getUserLandscapeIDs();
core.debug("User-installed landscapes: " + userLandscapes.length);
if(userLandscapes.length > 0) {
    core.debug("Your custom landscapes: " + userLandscapes.join(", "));
}

// Switch to ocean landscape with 2-second transition
LandscapeMgr.setCurrentLandscapeID("ocean", 2.0);

// Switch to zero landscape (simple ground plane)
LandscapeMgr.setCurrentLandscapeID("zero", 1.0);

// Check if successful
var success = LandscapeMgr.setCurrentLandscapeID("guereins");
if(success) {
    core.debug("Landscape changed successfully");
} else {
    core.debug("Failed to change landscape");
}

// Switch to Ocean landscape by name
LandscapeMgr.setCurrentLandscapeName("Ocean", 2.0);

// Switch to Guereins landscape
LandscapeMgr.setCurrentLandscapeName("Guereins");

var landscapeBrightness = LandscapeMgr.getCurrentLandscapeBrightness(false);
var lightBrightness = LandscapeMgr.getCurrentLandscapeBrightness(true);
core.debug("Landscape brightness: " + landscapeBrightness.toFixed(3) + ", Light layer: " + lightBrightness.toFixed(3));

// Set ocean as default landscape
var success = LandscapeMgr.setDefaultLandscapeID("ocean");
if(success) {
    core.debug("Default landscape updated to ocean");
}

var description = LandscapeMgr.getCurrentLandscapeHtmlDescription();
core.debug(description);
// Can be displayed in a UI element

// Increase cache size to 500 MB for faster landscape switching
LandscapeMgr.setCacheSize(500);

var newSize = LandscapeMgr.getCacheSize();
core.debug("New cache size: " + newSize + " MB");

var usedCache = LandscapeMgr.getCacheFilledSize();
var maxCache = LandscapeMgr.getCacheSize();
var percent = (usedCache / maxCache * 100).toFixed(1);
core.debug("Cache usage: " + usedCache + " / " + maxCache + " MB (" + percent + "%)");

// Preload multiple landscapes for a presentation
LandscapeMgr.precacheLandscape("guereins");
LandscapeMgr.precacheLandscape("ocean");
LandscapeMgr.precacheLandscape("zero");
core.debug("Landscapes preloaded");

// Check cache status
var cacheCount = LandscapeMgr.getCacheCount();
core.debug("Cache now contains " + cacheCount + " landscapes");

// Remove ocean landscape from cache
var removed = LandscapeMgr.removeCachedLandscape("ocean");
if(removed) {
    core.debug("Ocean landscape removed from cache");
}

if(LandscapeMgr.getFlagLandscape()) {
    core.debug("Landscape is visible");
} else {
    LandscapeMgr.setFlagLandscape(true);
    core.debug("Landscape enabled");
}

// Hide landscape to see the full sky
LandscapeMgr.setFlagLandscape(false);

// Show landscape again
LandscapeMgr.setFlagLandscape(true);

if(LandscapeMgr.getIsLandscapeFullyVisible()) {
    core.debug("Landscape is fully visible (opaque)");
} else {
    core.debug("Landscape is fading or hidden");
}

var sinMinAlt = LandscapeMgr.getLandscapeSinMinAltitudeLimit();
var minAlt = Math.asin(sinMinAlt) * 180 / Math.PI;
core.debug("Landscape minimum altitude: " + minAlt.toFixed(2) + "°");

if(LandscapeMgr.getFlagFog()) {
    core.debug("Fog is visible");
}

// Enable fog for atmospheric depth
LandscapeMgr.setFlagFog(true);

// Disable fog for clearer horizon
LandscapeMgr.setFlagFog(false);

if(LandscapeMgr.getFlagIllumination()) {
    core.debug("Illumination layer is visible");
}

// Enable city lights effect
LandscapeMgr.setFlagIllumination(true);

// Disable for a darker night landscape
LandscapeMgr.setFlagIllumination(false);

if(LandscapeMgr.getFlagLabels()) {
    core.debug("Landscape labels are visible");
}

// Show landscape labels
LandscapeMgr.setFlagLabels(true);

// Hide for a cleaner view
LandscapeMgr.setFlagLabels(false);

// Larger labels for better readability
LandscapeMgr.setLabelFontSize(18);

// Smaller labels for less clutter
LandscapeMgr.setLabelFontSize(12);

// Rotate labels for better readability on tilted labels
LandscapeMgr.setLabelAngle(45);

// No rotation
LandscapeMgr.setLabelAngle(0);

// Set labels to green
var green = core.vec3f(0.2, 0.8, 0.2);
LandscapeMgr.setLabelColor(green);

// Set labels to white
var white = core.vec3f(1.0, 1.0, 1.0);
LandscapeMgr.setLabelColor(white);

// Make landscape semi-transparent to see stars through ground
LandscapeMgr.setFlagLandscapeUseTransparency(true);
LandscapeMgr.setLandscapeTransparency(0.5);

// Make fully opaque
LandscapeMgr.setLandscapeTransparency(0.0);

if(LandscapeMgr.getFlagLandscapeUseTransparency()) {
    core.debug("Landscape transparency is enabled");
}

// Enable transparency mode
LandscapeMgr.setFlagLandscapeUseTransparency(true);
LandscapeMgr.setLandscapeTransparency(0.3);

// Disable transparency
LandscapeMgr.setFlagLandscapeUseTransparency(false);

if(LandscapeMgr.getFlagPolyLineOnlyDisplayed()) {
    core.debug("Only horizon polyline is visible");
}

// Show only the measured horizon line
LandscapeMgr.setFlagPolyLineOnlyDisplayed(true);

// Show full landscape texture
LandscapeMgr.setFlagPolyLineOnlyDisplayed(false);

// Thicker horizon line for better visibility
LandscapeMgr.setPolyLineThickness(2);

// Thin line for precise measurement
LandscapeMgr.setPolyLineThickness(1);

// Set horizon line to bright red
var red = core.vec3f(1.0, 0.0, 0.0);
LandscapeMgr.setPolyLineColor(red);

// Set horizon line to cyan
var cyan = core.vec3f(0.0, 0.8, 0.9);
LandscapeMgr.setPolyLineColor(cyan);

if(LandscapeMgr.getFlagLandscapeUseMinimalBrightness()) {
    core.debug("Landscape will not go below minimal brightness");
}

// Prevent landscape from becoming too dark
LandscapeMgr.setFlagLandscapeUseMinimalBrightness(true);

// Allow natural darkness
LandscapeMgr.setFlagLandscapeUseMinimalBrightness(false);

if(LandscapeMgr.getFlagLandscapeSetsMinimalBrightness()) {
    core.debug("Using landscape-specific minimal brightness");
}

// Use each landscape's own minimal brightness setting
LandscapeMgr.setFlagLandscapeSetsMinimalBrightness(true);

// Use global minimal brightness for all landscapes
LandscapeMgr.setFlagLandscapeSetsMinimalBrightness(false);

// Increase minimal brightness for better visibility
LandscapeMgr.setDefaultMinimalBrightness(0.05);

// Allow landscapes to get very dark
LandscapeMgr.setDefaultMinimalBrightness(0.001);

if(LandscapeMgr.getFlagLandscapeSetsLocation()) {
    core.debug("Changing landscape will move observer location");
}

// Disable automatic location change
LandscapeMgr.setFlagLandscapeSetsLocation(false);
LandscapeMgr.setCurrentLandscapeID("ocean");

// Enable to return to location-based switching
LandscapeMgr.setFlagLandscapeSetsLocation(true);

if(LandscapeMgr.getFlagUseLightPollutionFromDatabase()) {
    core.debug("Using light pollution data from location database");
}

// Use automatic light pollution from location
LandscapeMgr.setFlagUseLightPollutionFromDatabase(true);

// Manual control of light pollution
LandscapeMgr.setFlagUseLightPollutionFromDatabase(false);

// Increase light pollution for urban simulation
LandscapeMgr.increaseLightPollution();
core.debug("Light pollution increased");

// Increase multiple steps
for(var i = 0; i < 3; i++) {
    core.wait(0.5);
    LandscapeMgr.increaseLightPollution();
}

// Reduce light pollution for dark sky simulation
LandscapeMgr.reduceLightPollution();
core.debug("Light pollution reduced");

// Cycle through all light pollution levels
LandscapeMgr.cyclicChangeLightPollution();

// Use in a loop to demonstrate all levels
for(var i = 0; i < 9; i++) {
    core.wait(1);
    LandscapeMgr.cyclicChangeLightPollution();
    core.debug("Cycled to next level");
}

if(LandscapeMgr.getFlagCardinalPoints()) {
    core.debug("Cardinal points (N,S,E,W) are visible");
}

// Show cardinal points
LandscapeMgr.setFlagCardinalPoints(true);

// Hide cardinal points
LandscapeMgr.setFlagCardinalPoints(false);

if(LandscapeMgr.getFlagOrdinalPoints()) {
    core.debug("Ordinal points (NE,SE,SW,NW) are visible");
}

if(LandscapeMgr.getFlagOrdinal16WRPoints()) {
    core.debug("16-wind compass points are visible");
}

if(LandscapeMgr.getFlagOrdinal32WRPoints()) {
    core.debug("32-wind compass points are visible");
}

// Set cardinal points to bright white
var white = core.vec3f(1.0, 1.0, 1.0);
LandscapeMgr.setColorCardinalPoints(white);

// Set to red for night mode
var red = core.vec3f(1.0, 0.2, 0.2);
LandscapeMgr.setColorCardinalPoints(red);

// Set to gold
var gold = core.vec3f(1.0, 0.84, 0.0);
LandscapeMgr.setColorCardinalPoints(gold);

if(LandscapeMgr.getFlagAtmosphere()) {
    core.debug("Atmosphere is visible");
} else {
    LandscapeMgr.setFlagAtmosphere(true);
}

// Enable atmosphere for realistic sky
LandscapeMgr.setFlagAtmosphere(true);

// Disable atmosphere for space-like view
LandscapeMgr.setFlagAtmosphere(false);

// Toggle atmosphere
var current = LandscapeMgr.getFlagAtmosphere();
LandscapeMgr.setFlagAtmosphere(!current);

// Switch to classic Preetham model
LandscapeMgr.setAtmosphereModel("preetham");

// Switch to ShowMySky (physically based)
// LandscapeMgr.setAtmosphereModel("showmysky");

if(LandscapeMgr.getAtmosphereShowMySkyStoppedWithError()) {
    core.debug("ShowMySky failed, check console for details");
}

// Disable blue sky effect (useful for special shots)
LandscapeMgr.setFlagAtmosphereNoScatter(true);

// Re-enable normal atmosphere
LandscapeMgr.setFlagAtmosphereNoScatter(false);

// Slow, dramatic fade
LandscapeMgr.setAtmosphereFadeDuration(2.0);
LandscapeMgr.setFlagAtmosphere(false);

// Fast fade (default)
LandscapeMgr.setAtmosphereFadeDuration(0.5);

// Set high quality for eclipse observation
LandscapeMgr.setAtmosphereEclipseSimulationQuality(2);

// Use low quality for better performance
LandscapeMgr.setAtmosphereEclipseSimulationQuality(0);

if(LandscapeMgr.getFlagAtmosphereZeroOrderScattering()) {
    core.debug("Zero-order scattering enabled");
}

// Get opacity at zenith (straight up)
var zenithDir = core.vec3d(0, 0, 1);
var opacity = LandscapeMgr.getLandscapeOpacity(zenithDir);
core.debug("Zenith opacity: " + opacity);

// Get opacity at 10 degrees altitude toward East
var az = 90 * Math.PI / 180;
var alt = 10 * Math.PI / 180;
var dir = core.vec3d(Math.cos(az) * Math.cos(alt), Math.sin(az) * Math.cos(alt), Math.sin(alt));
var horizonOpacity = LandscapeMgr.getLandscapeOpacity(dir);
core.debug("Horizon opacity: " + horizonOpacity);

// Check opacity at due east on the horizon
var eastOpacity = LandscapeMgr.getLandscapeOpacity(90, 0);
core.debug("East horizon opacity: " + eastOpacity);

// Check opacity at north celestial pole direction
var northOpacity = LandscapeMgr.getLandscapeOpacity(0, 45);

// Use for sunrise calculation
for(var alt = -2; alt <= 2; alt += 0.5) {
    var op = LandscapeMgr.getLandscapeOpacity(90, alt);
    core.debug("East at alt=" + alt + "°: opacity=" + op);
}

// Apply a warm sunset tint
var sunsetTint = core.vec3f(1.0, 0.6, 0.3);
LandscapeMgr.setLandscapeTint(sunsetTint);

// Reset to normal (white)
var white = core.vec3f(1.0, 1.0, 1.0);
LandscapeMgr.setLandscapeTint(white);

if(LandscapeMgr.getFlagLandscapeAutoSelection()) {
    core.debug("Landscape auto-selection is ON");
} else {
    core.debug("Landscape auto-selection is OFF");
}

// Enable automatic landscape selection
LandscapeMgr.setFlagLandscapeAutoSelection(true);

// Disable manual control
LandscapeMgr.setFlagLandscapeAutoSelection(false);

if(LandscapeMgr.getFlagEnvironmentAutoEnable()) {
    core.debug("Environment auto-enable is ON");
}

// Rotate the landscape by 45 degrees
LandscapeMgr.setZRotation(45.0);

// Reset to original orientation
LandscapeMgr.setZRotation(0.0);

// Install a landscape from a ZIP file
var landscapeId = LandscapeMgr.installLandscapeFromArchive("/path/to/my_landscape.zip", true);
if(landscapeId) {
    core.debug("Landscape installed: " + landscapeId);
} else {
    core.debug("Installation failed");
}

// Remove a previously installed landscape
var removed = LandscapeMgr.removeLandscape("my_custom_landscape");
if(removed) {
    core.debug("Landscape removed successfully");
} else {
    core.debug("Failed to remove landscape");
}

var sizeBytes = LandscapeMgr.loadLandscapeSize("guereins");
var sizeMB = sizeBytes / (1024 * 1024);
core.debug("Landscape size: " + sizeMB.toFixed(2) + " MB");

LandscapeMgr.showMessage("Landscape changed to Ocean");
core.wait(3);
LandscapeMgr.clearMessage();
